mapper.select:


    a.JSBJ != 'Y'
    and a.ZSPM_DM = '399001910'
    and a.RKRQ between '2020-02-01' and '2020-12-31'
    and a.dept_id = #{req.deptId}
    and a.SHXYDM = #{req.shxydm}
    and a.NSRMC like concat('%', #{req.nsrmc}, '%')
    and a.ZGSWJ_DM = #{req.zgswjDm}
    and a.ZSPM_DM = #{req.zspmDm}
    and a.SKSSQQ >= #{req.skssqq}
    and a.SKSSQZ <= #{req.skssqz}
    and a.YBTSE = #{req.ybtse}
    and a.HKPCH = #{req.hkpch}
    and b.HKPZH = #{req.hkpzh}
    and b.FBBJ = #{req.fbbj}
    and a.RKRQ between #{req.beginRkrq} and #{req.endRkrq}
    and a.JSRQ between #{req.beginJsrq} and #{req.endJsrq}
    and b.FBRQ between #{req.beginFbrq} and #{req.endFbrq}

order by a.RKRQ desc
